var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"제법이군. 더 덤벼 보겠느냐?","JPN":"やるのう。もっと続けるか？","ENG":"Impressive. Ready for more?","TWN":"不錯，還要再來嗎？"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크으으……</b>","JPN":"<b>グルル……</b>","ENG":"<b>Khhhkkk...</b>","TWN":"<b>咳呃呃……</b>"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"흐음, 시시하긴.","JPN":"ふん、つまらぬのう。","ENG":"Hmm. Underwhelming.","TWN":"哼，真無聊。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"벌써 지쳤느냐? 날 잡아먹겠다고 기세등등할 때는 언제고.","JPN":"もう疲れたのか？　妾を食い殺すと意気込んでいたくせに？","ENG":"Tired already? I thought you were eager to devour me.","TWN":"已經累了嗎？剛才不是還一副凶神惡煞地想要吃掉我？"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이름이……. 아, 그래. 레비아탄이라고 했지.","JPN":"名が……そうそう。レヴィアタンと言っておったな。","ENG":"What was your name... Oh, right. Leviathan.","TWN":"名字……啊，對了，叫利維坦對吧。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"자아, 어서 일어나서 덤벼 보아라.","JPN":"さあ、立ってもう一度かかってきてみろ。","ENG":"Now, stand up and face me again.","TWN":"好了，快站起來，繼續吧。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"내 친히 네가 누비던 <color=#ffd34c>바다</color>에까지 와 주지 않았느냐.","JPN":"其方が最も動きやすい<color=#ffd34c>海</color>までわざわざ来てやったではないか。","ENG":"I came all the way to the <color=#ffd34c>ocean</color>that you dearly love.","TWN":"我不是親自來到你生活的<color=#ffd34c>大海</color>了嗎。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"신을 물어뜯겠다고 했던가? 이 정도에 꺾일 거였으면 이빨을 드러내지 말았어야지.","JPN":"神を嚙み千切るのではなかったか？　この程度で戦意喪失するくらいなら最初から牙を向けるでない。","ENG":"Biting and tearing down a god? You shouldn’t have shown your teeth if this was everything you had.","TWN":"不是說要吞掉神嗎？這種程度就被打倒的話，一開始就不該露出獠牙。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크륵……. 큭…….</b>","JPN":"<b>グルル……グル……</b>","ENG":"<b>Krrr... Krgh...</b>","TWN":"<b>呃唔……呃……</b>"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크흐흐흐…….</b>","JPN":"<b>クフフフ……</b>","ENG":"<b>Ke he he he he...</b>","TWN":"<b>咳呵呵呵……</b>"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐음? 뭐가 그리 우습지?","JPN":"ふむ？　何が面白いのじゃ？","ENG":"Hmm? What’s so funny?","TWN":"嗯？什麼事那麼好笑？"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>크흐, 흐으……. 그야 우습고 말고.</b>","JPN":"<b>くふ、ふう……そりゃ面白いさ。</b>","ENG":"<b>Ke he, he... Of course, it's funny.</b>","TWN":"<b>咳呵……當然好笑了。</b>"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NEXT_NULL","text":{"KOREA":"<b>마지막 사냥이……. 하필이면 사냥꾼을 사냥감으로 착각한 꼴이었다니.</b>","JPN":"<b>最後の狩りが……まさか狙った獲物に逆に狩られる気分だったなんて。</b>","ENG":"<b>The irony of mistaking a predator for a prey... On my last hunt.</b>","TWN":"<b>最後的狩獵……把獵人錯當成了獵物。</b>"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐응, 재밌군.","JPN":"ふむ、面白いのう。","ENG":"Hmm, interesting.","TWN":"唔，有意思。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"골이 비었어도 마왕이란 것이, 그리 쉽게 패배를 인정하기라도 할 셈인가?","JPN":"いくら骨抜きだろうと、魔王は魔王。そう簡単に敗北を認めてもいいのか？","ENG":"Foolish as you sound, you are still a Demon Lord. Are you going to accept your defeat that easily?","TWN":"就算腦袋空空，你也算是個魔王，那麼輕易就想認輸了嗎？"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아니면 날 방심시키기라도 하려고?","JPN":"それとも妾を油断させる作戦か？","ENG":"Or are you just trying to lower my guard?","TWN":"還是說想讓我掉以輕心？"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"하긴, 짐승인 네게 품격 따위를 바라는 것도 과하겠지만.","JPN":"まぁ、獣である其方に品格など望むべくもないが。","ENG":"To be fair, there's only so much I could ask of a mere beast.","TWN":"但實話說，期望身為畜生的你具備品格什麼的，是我要求過分了。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};